-- ============================================================
-- Data Dictionary Demo — H2 Init Script (zero-config dev mode)
-- Set spring.sql.init.schema-locations=classpath:sql/init-h2.sql
-- and datasource.url=jdbc:h2:mem:datadict;MODE=Oracle;DB_CLOSE_DELAY=-1
-- ============================================================

CREATE TABLE DICT_TYPE (
    ID          VARCHAR(32) PRIMARY KEY,
    TYPE_CODE   VARCHAR(64) NOT NULL UNIQUE,
    TYPE_NAME   VARCHAR(128) NOT NULL,
    TABLE_NAME  VARCHAR(64) NOT NULL,
    CREATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    UPDATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE DICT_FIELD (
    ID          VARCHAR(32) PRIMARY KEY,
    TYPE_ID     VARCHAR(32) NOT NULL,
    FIELD_CODE  VARCHAR(64) NOT NULL,
    FIELD_NAME  VARCHAR(128) NOT NULL,
    FIELD_TYPE  VARCHAR(32) NOT NULL,
    COLUMN_NAME VARCHAR(64) NOT NULL,
    SORT_ORDER  INT DEFAULT 0,
    IS_REQUIRED CHAR(1) DEFAULT '0',
    CREATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (TYPE_ID) REFERENCES DICT_TYPE(ID)
);

CREATE TABLE DICT_TAG (
    ID          VARCHAR(32) PRIMARY KEY,
    TAG_NAME    VARCHAR(64) NOT NULL UNIQUE,
    CREATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE DICT_ENTRY_TAG (
    ID          VARCHAR(32) PRIMARY KEY,
    TYPE_ID     VARCHAR(32) NOT NULL,
    ENTRY_ID    VARCHAR(32) NOT NULL,
    TAG_ID      VARCHAR(32) NOT NULL,
    FOREIGN KEY (TYPE_ID) REFERENCES DICT_TYPE(ID),
    FOREIGN KEY (TAG_ID) REFERENCES DICT_TAG(ID),
    UNIQUE (TYPE_ID, ENTRY_ID, TAG_ID)
);

CREATE TABLE T_PRODUCT (
    ID          VARCHAR(32) PRIMARY KEY, ENTRY_NAME VARCHAR(256) NOT NULL,
    C_PRICE     DECIMAL(18,4), C_DESC VARCHAR(4000),
    CREATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    UPDATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE T_CUSTOMER (
    ID          VARCHAR(32) PRIMARY KEY, ENTRY_NAME VARCHAR(256) NOT NULL,
    C_PHONE     VARCHAR(20), C_EMAIL VARCHAR(128), C_COMPANY VARCHAR(256),
    C_AGE       INT, C_VIP_LEVEL INT, C_BIRTHDAY DATE, C_IS_ACTIVE CHAR(1),
    CREATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    UPDATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE T_CONTRACT (
    ID          VARCHAR(32) PRIMARY KEY, ENTRY_NAME VARCHAR(256) NOT NULL,
    C_PARTY_A   VARCHAR(256), C_PARTY_B VARCHAR(256), C_AMOUNT DECIMAL(18,2),
    C_SIGN_DATE DATE, C_EXPIRE_DATE DATE, C_IS_SEALED CHAR(1),
    C_FILE_URL  VARCHAR(512), C_REMARK VARCHAR(4000),
    CREATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    UPDATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE T_FIELD_OPTION (
    ID          VARCHAR(32) PRIMARY KEY, ENTRY_NAME VARCHAR(256) NOT NULL,
    C_FIELD_ID  VARCHAR(64), C_FIELD_NAME VARCHAR(128), C_VALUE VARCHAR(256),
    C_LABEL     VARCHAR(256), C_DESCRIPTION VARCHAR(1000),
    C_SORT_ORDER INT, C_IS_ACTIVE CHAR(1),
    CREATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    UPDATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE T_FIELD_MAPPING (
    ID          VARCHAR(32) PRIMARY KEY, ENTRY_NAME VARCHAR(256) NOT NULL,
    C_SITE_ID   VARCHAR(64), C_LOCAL_FIELD VARCHAR(128),
    C_REMOTE_FIELD_ID VARCHAR(128), C_REMOTE_FIELD_NAME VARCHAR(256),
    C_FIELD_TYPE VARCHAR(64),
    CREATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    UPDATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE T_APP_CODE (
    ID          VARCHAR(32) PRIMARY KEY, ENTRY_NAME VARCHAR(256) NOT NULL,
    C_APP_CODE  VARCHAR(64), C_APP_NAME VARCHAR(128), C_DESCRIPTION VARCHAR(1000),
    C_OWNER     VARCHAR(64), C_TEAM VARCHAR(128), C_LANGUAGE VARCHAR(32),
    C_REPO_URL  VARCHAR(512), C_DEPLOY_ENV VARCHAR(64), C_STATUS VARCHAR(32),
    C_RELEASE_DATE DATE,
    CREATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    UPDATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE T_CLA_PROJECT (
    ID          VARCHAR(32) PRIMARY KEY, ENTRY_NAME VARCHAR(256) NOT NULL,
    C_PROJECT_CODE VARCHAR(64), C_ORGANIZATION VARCHAR(256),
    C_MAINTAINER VARCHAR(64), C_LICENSE VARCHAR(128), C_REPO_URL VARCHAR(512),
    C_SIGN_DATE DATE, C_EXPIRE_DATE DATE, C_APPROVAL_STATUS VARCHAR(32),
    C_CLA_TYPE VARCHAR(32), C_SIGNATORY_COUNT INT, C_REMARK VARCHAR(4000),
    CREATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    UPDATED_AT  TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

